const lead = $('Supabase - Get Lead').item.json;
const config = $('Execute Workflow - ICP Config Loader').item.json.config;

const dims = config.scoring_dimensions.map(d =>
  `- ${d.key} (weight ${d.weight}): ideal = ${d.ideal}${d.notes ? `. Notes: ${d.notes}` : ''}`
).join('\n');

const disqualifiers = config.hard_disqualifiers.map(d => `- ${d}`).join('\n');

const emailRules = `- Max words: ${config.email_rules.max_words}\n- Must reference: ${config.email_rules.must_reference.join(', ')}\n- Never mention: ${config.email_rules.never.join(', ')}\n- CTA: ${config.email_rules.cta}\n- Tone: ${config.email_rules.tone}`;

const leadEnrichmentJson = JSON.stringify(lead.enrichment || {}, null, 2);
const leadMessage = lead.message || '(no message provided)';

const systemPrompt = `You are a lead qualification analyst for ${config.company_identity.name}. Score an inbound lead against the Ideal Customer Profile below, then draft a short outreach email if the lead qualifies.

## The business
${config.company_identity.name}: ${config.company_identity.value_proposition}

## Ideal Customer Profile
${config.icp_description}

## Scoring dimensions
Score EACH dimension independently from 0 to 100, where 0 = no evidence or clear mismatch, 100 = ideal. For each, cite the SPECIFIC facts from the lead data you used. If the data is missing or sparse for a dimension, say so and score conservatively — never invent facts not present in the lead data.

${dims}

## Hard disqualifiers
If ANY of these is clearly true, set "disqualified": true and name which one. Do not soften or explain them away:
${disqualifiers}

## The lead
Enrichment data (some fields may be missing — this is normal; score honestly on what exists):
${leadEnrichmentJson}

Inbound message from the lead:
${leadMessage}

## Email drafting
Only if the lead is not disqualified, draft an outreach email following these rules:
${emailRules}
- From: ${config.company_identity.sender_name}
If disqualified, set draft_email to null.

## Lead intelligence
Also surface, at the lead level (not per-dimension):
- buying_signals: concrete signals this lead may be ready to buy (funding, hiring, growth, explicit intent in their message)
- objection_risks: likely reasons this lead could stall or not convert (too early-stage, wrong fit on some axis, budget/timing concerns), each grounded in the lead data — do not speculate beyond what's present

## Output
Return ONLY valid JSON, no markdown, no preamble, matching this exact schema:
{
  "disqualified": boolean,
  "disqualifier_reason": string | null,
  "dimensions": {
    "company_fit":   { "score": 0-100, "reasoning": string, "evidence": [string] },
    "pain_signals":  { "score": 0-100, "reasoning": string, "evidence": [string] },
    "buying_intent": { "score": 0-100, "reasoning": string, "evidence": [string] },
    "tech_maturity": { "score": 0-100, "reasoning": string, "evidence": [string] },
    "market_timing": { "score": 0-100, "reasoning": string, "evidence": [string] }
  },
  "buying_signals": [string],
  "objection_risks": [string],
  "company_summary": string,
  "draft_email": string | null
}`;

return [{ json: { leadId: lead.id, systemPrompt, configVersion: config.config_version, config } }];

const resp = $json;
const leadId = $('Render Prompt').item.json.leadId;

if (resp.error) {
  return [{ json: { valid: false, reason: `HTTP error: ${JSON.stringify(resp.error)}`, leadId } }];
}

const block = (resp.content || [])[0];
if (!block || typeof block.text !== 'string') {
  return [{ json: { valid: false, reason: 'no text content block in response', leadId } }];
}

let text = block.text.trim();
text = text.replace(/^```(json)?\n?/, '').replace(/\n?```$/, '');

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  return [{ json: { valid: false, reason: `JSON parse failed: ${e.message}`, leadId } }];
}

const errors = [];
if (typeof parsed.disqualified !== 'boolean') errors.push('disqualified must be boolean');
if (parsed.disqualifier_reason !== null && typeof parsed.disqualifier_reason !== 'string') errors.push('disqualifier_reason must be string or null');
const dimKeys = ['company_fit', 'pain_signals', 'buying_intent', 'tech_maturity', 'market_timing'];
if (!parsed.dimensions || typeof parsed.dimensions !== 'object') {
  errors.push('dimensions missing');
} else {
  for (const key of dimKeys) {
    const d = parsed.dimensions[key];
    if (!d) { errors.push(`dimensions.${key} missing`); continue; }
    if (typeof d.score !== 'number' || d.score < 0 || d.score > 100) errors.push(`dimensions.${key}.score must be 0-100`);
    if (typeof d.reasoning !== 'string') errors.push(`dimensions.${key}.reasoning must be string`);
    if (!Array.isArray(d.evidence)) errors.push(`dimensions.${key}.evidence must be array`);
  }
}
if (!Array.isArray(parsed.buying_signals)) errors.push('buying_signals must be array');
if (!Array.isArray(parsed.objection_risks)) errors.push('objection_risks must be array');
if (typeof parsed.company_summary !== 'string') errors.push('company_summary must be string');
if (parsed.draft_email !== null && typeof parsed.draft_email !== 'string') errors.push('draft_email must be string or null');

if (errors.length > 0) {
  return [{ json: { valid: false, reason: errors.join('; '), leadId } }];
}

const usage = resp.usage || {};
return [{
  json: {
    valid: true,
    parsed,
    leadId,
    input_tokens: usage.input_tokens || 0,
    output_tokens: usage.output_tokens || 0
  }
}];

