const { parsed, leadId, input_tokens, output_tokens } = $json;
const config = $('Render Prompt').item.json.config;

let weightedTotal = 0;
for (const dim of config.scoring_dimensions) {
  const score = (parsed.dimensions[dim.key] && parsed.dimensions[dim.key].score) || 0;
  weightedTotal += (score * dim.weight) / 100;
}
weightedTotal = Math.round(weightedTotal);

const icpScore = parsed.disqualified ? Math.min(weightedTotal, 10) : weightedTotal;

const { hot, review, nurture } = config.thresholds;
let tier;
if (icpScore >= hot) tier = 'hot';
else if (icpScore >= review) tier = 'review';
else if (icpScore >= nurture) tier = 'nurture';
else tier = 'discard';

const deliverDraft = tier !== 'discard';

// Haiku 4.5 pricing as of 2026-07-22: $1.00/1M input tokens, $5.00/1M output tokens (docs/DECISIONS.md)
const costUsd = (input_tokens / 1e6) * 1.00 + (output_tokens / 1e6) * 5.00;

const intelligence = {
  disqualified: parsed.disqualified,
  disqualifier_reason: parsed.disqualifier_reason,
  dimensions: parsed.dimensions,
  buying_signals: parsed.buying_signals,
  objection_risks: parsed.objection_risks,
  company_summary: parsed.company_summary,
  draft_email: deliverDraft ? parsed.draft_email : null,
  icp_score: icpScore,
  tier,
  prompt_version: 'lead-scoring-v1',
  config_version: config.config_version,
  scored_at: new Date().toISOString(),
  input_tokens,
  output_tokens,
  cost_usd: Math.round(costUsd * 1e6) / 1e6
};

return [{ json: { leadId, intelligence } }];
